import { withDb } from "./db.mjs";

// JSONB-based schema: key tables store a `doc` JSONB column alongside indexed scalar columns.
// If the tables exist without a `doc` column (old normalized schema), drop and recreate them.
async function tableHasDocColumn(client, tableName) {
  const res = await client.query(
    `SELECT column_name FROM information_schema.columns WHERE table_name = $1 AND column_name = 'doc'`,
    [tableName]
  );
  return res.rows.length > 0;
}

async function tableExists(client, tableName) {
  const res = await client.query(
    `SELECT table_name FROM information_schema.tables WHERE table_name = $1`,
    [tableName]
  );
  return res.rows.length > 0;
}

export async function ensureSchema(client) {
  // Drop old normalized tables that lack the doc column so we can recreate them as JSONB tables.
  for (const tbl of ['invoices', 'orders', 'accounts']) {
    const exists = await tableExists(client, tbl);
    if (exists && !(await tableHasDocColumn(client, tbl))) {
      await client.query(`DROP TABLE IF EXISTS ${tbl} CASCADE`);
    }
  }

  await client.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id TEXT PRIMARY KEY,
      doc JSONB NOT NULL
    )
  `);
  await client.query(`
    CREATE TABLE IF NOT EXISTS orders (
      order_id TEXT PRIMARY KEY,
      account_id TEXT,
      doc JSONB NOT NULL
    )
  `);
  await client.query(`
    CREATE TABLE IF NOT EXISTS invoices (
      invoice_id TEXT PRIMARY KEY,
      account_id TEXT,
      order_id TEXT,
      doc JSONB NOT NULL
    )
  `);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}

